function translate(q,tl='krcn') {
  return new Promise((resolve,reject)=>{
    if(!q) return resolve(null);
    // let url='https://translate.kakao.com/translator/translate.json?lang='+tl+'&q='+encodeURIComponent(q);
    // console.log(url)
    https.request({
      hostname:'translate.kakao.com',
      path:'/translator/translate.json?lang='+tl+'&q='+encodeURIComponent(q),
      method:'POST',
      headers:{
        'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
        Cookie: `webid=0d818510e78811e79ff7000af759d1a0; _kawlt=Cr9-pvZvCEhdwC5ZfZd6W9CgkIr0GbeFL_g-UJAyDKeqoQxoiKJakRVooMjzg1wnVtRyjGQHNNKf6VsN9o-liGXYvt8deaTKU_R2Ap_cqEM; _karmt=kTLljGV5GIgAmAjyN5_jD2u4n4dfY3L7KUEbo_k7JX3KwrngnpZgQPhSG9VEg28l; _kawltea=1514466172; _karmtea=1514476972; _kadu=b_L7HXy-SJTCpElB_1534159141349; hideMiniTooltip=Y; TIARA=-4IFmhzckVeZOs1HqdB9Pfr_tQ8oDwS.fJEqO2U5ThAm8PMVqmgd2U1qNIuEO.z.GGKYq5CUhrCvW3fVnCggp4AQOaQTWFFW`
      }
    }, function(res){
      if(res.statusCode!==200) resolve(null);
      res.setEncoding('utf8');
      console.log(res.statusCode)
      res.on('data',d=>{
        resolve(d);
    }).on('error',e=>resolve(null));
  });  
  });
}



module.exports=translate;

